exec("""from __future__ import annotations\nimport json, shutil\nfrom datetime import datetime, timedelta, timezone\nfrom pathlib import Path\nROOT = Path(__file__).resolve().parents[1]; OUTPUT_DIR = ROOT / 'output'; PUBLIC_DIR = ROOT / 'public'; JST = timezone(timedelta(hours=9), 'JST')\ndef _read(path, default):\n    return json.loads(path.read_text(encoding='utf-8')) if path.exists() else default\ndef _write(path, value):\n    path.parent.mkdir(parents=True, exist_ok=True); path.write_text(json.dumps(value, ensure_ascii=False, indent=2), encoding='utf-8')\ndef _copy(src, dest):\n    if src.exists(): dest.parent.mkdir(parents=True, exist_ok=True); shutil.copy2(src, dest)\ndef build_metadata(products, opportunities):\n    return {'generated_at_jst': datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z'), 'product_count': len(products), 'opportunity_count': len(opportunities), 'verified_exact_count': len([x for x in opportunities if x.get('match_status') == 'VERIFIED_EXACT_TRIPLE_CHECKED']), 'positive_gap_count': len([x for x in opportunities if isinstance(x.get('gross_gap_yen'), int) and x.get('gross_gap_yen') > 0]), 'source_site': 'https://newenoking-kaitori.com/', 'mode': 'GitHub Actions + GitHub Pages static dashboard'}\ndef index_html():\n    return '''<!doctype html><html lang="ja"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Enoking Cloud Monitor</title><style>body{font-family:system-ui,-apple-system,sans-serif;margin:0;background:#07111f;color:#eef5ff}main,header{max-width:1200px;margin:auto;padding:20px}a{color:#62d2ff}.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:12px}.card,section{background:#101b2d;border:1px solid #293a55;border-radius:16px;padding:14px;margin:14px 0}input,select{padding:10px;border-radius:10px;border:1px solid #293a55;background:#091527;color:#eef5ff}.toolbar{display:grid;grid-template-columns:1fr 180px;gap:10px}table{width:100%;border-collapse:collapse;min-width:980px}th,td{padding:9px;border-bottom:1px solid #293a55;text-align:left}th{position:sticky;top:0;background:#13223a}.wrap{overflow:auto;max-height:70vh}.good{color:#49d17d}.warn{color:#ffca63}.bad{color:#ff7676}.badge{border:1px solid #293a55;border-radius:99px;padding:2px 7px;font-size:12px;display:inline-block}.links a{display:inline-block;margin:2px 4px 2px 0;border:1px solid #293a55;border-radius:99px;padding:3px 7px;text-decoration:none}</style></head><body><header><h1>Enoking Cloud Monitor</h1><p>公開商品情報を毎日クラウドで取得し、JAN・買取価格・仕入れ候補・価格差・トリプルチェック状態を表示します。</p><p><a href="downloads/latest_enoking_products.csv">products.csv</a> / <a href="downloads/latest_enoking_products.xlsx">products.xlsx</a> / <a href="downloads/latest_opportunities.csv">opportunities.csv</a></p></header><main><div id="cards" class="cards"></div><section><h2>仕入れ先・価格差</h2><div class="toolbar"><input id="q" placeholder="JAN・商品名で検索"><select id="f"><option value="all">全て</option><option value="positive">価格差プラス</option><option value="verified">トリプルチェック済</option></select></div><div class="wrap"><table id="op"></table></div></section><section><h2>取得済み商品</h2><div class="wrap"><table id="prod"></table></div></section></main><script>const yen=v=>v==null?'-':new Intl.NumberFormat('ja-JP',{style:'currency',currency:'JPY',maximumFractionDigits:0}).format(v);const esc=v=>String(v??'').replace(/[&<>\"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;'}[c]));let products=[],opps=[],meta={};function links(r){return '<div class="links">'+Object.entries(r.search_links||{}).map(([k,u])=>`<a href="${esc(u)}" target="_blank">${esc(k)}</a>`).join('')+'</div>'}function render(){document.getElementById('cards').innerHTML=[['商品数',meta.product_count??products.length],['候補行',meta.opportunity_count??opps.length],['価格差プラス',meta.positive_gap_count??0],['トリプルチェック済',meta.verified_exact_count??0],['生成',meta.generated_at_jst??'-']].map(x=>`<div class="card"><small>${esc(x[0])}</small><h2>${esc(x[1])}</h2></div>`).join('');const q=document.getElementById('q').value.toLowerCase(),f=document.getElementById('f').value;let rows=opps.filter(r=>(!q||[r.jan,r.product_name,r.supplier,r.supplier_product_name].join(' ').toLowerCase().includes(q))&&(f!='positive'||Number(r.gross_gap_yen)>0)&&(f!='verified'||r.match_status=='VERIFIED_EXACT_TRIPLE_CHECKED'));document.getElementById('op').innerHTML='<tr><th>判定</th><th>JAN</th><th>商品</th><th>買取</th><th>仕入れ</th><th>差額</th><th>検索</th></tr>'+rows.map(r=>`<tr><td><span class="badge ${r.match_status=='VERIFIED_EXACT_TRIPLE_CHECKED'?'good':'warn'}">${esc(r.match_status)}</span><br><small>${esc(r.warning)}</small></td><td>${esc(r.jan)}</td><td>${esc(r.product_name)}<br><small>${esc(r.category)}</small></td><td>${yen(r.enoking_buy_price_yen)}</td><td>${r.supplier_url?`<a href="${esc(r.supplier_url)}" target="_blank">${esc(r.supplier)}</a>`:esc(r.supplier)}<br>${yen(r.supplier_price_yen)}</td><td class="${Number(r.gross_gap_yen)>0?'good':''}">${yen(r.gross_gap_yen)}</td><td>${links(r)}</td></tr>`).join('');document.getElementById('prod').innerHTML='<tr><th>JAN</th><th>商品</th><th>カテゴリ</th><th>買取</th><th>備考</th></tr>'+products.filter(p=>!q||[p.jan,p.product_name,p.category].join(' ').toLowerCase().includes(q)).map(p=>`<tr><td>${esc(p.jan)}</td><td>${esc(p.product_name)}</td><td>${esc(p.category)}</td><td>${yen(p.buy_price_yen)}</td><td>${esc(p.notes)}</td></tr>`).join('')}Promise.all([fetch('data/products.json').then(r=>r.json()).catch(()=>[]),fetch('data/opportunities.json').then(r=>r.json()).catch(()=>[]),fetch('data/metadata.json').then(r=>r.json()).catch(()=>({}))]).then(v=>{[products,opps,meta]=v;render();q.oninput=render;f.oninput=render})</script></body></html>'''\ndef build_static_site(output_dir: Path = OUTPUT_DIR, public_dir: Path = PUBLIC_DIR):\n    products = _read(output_dir / 'latest_enoking_products.json', []); opps = _read(output_dir / 'latest_opportunities.json', []); meta = build_metadata(products, opps)\n    if public_dir.exists(): shutil.rmtree(public_dir)\n    (public_dir / 'data').mkdir(parents=True, exist_ok=True); (public_dir / 'downloads').mkdir(parents=True, exist_ok=True)\n    (public_dir / 'index.html').write_text(index_html(), encoding='utf-8'); _write(public_dir / 'data' / 'products.json', products); _write(public_dir / 'data' / 'opportunities.json', opps); _write(public_dir / 'data' / 'metadata.json', meta); (public_dir / '.nojekyll').write_text('', encoding='utf-8')\n    _copy(output_dir / 'latest_enoking_products.csv', public_dir / 'downloads' / 'latest_enoking_products.csv'); _copy(output_dir / 'latest_enoking_products.xlsx', public_dir / 'downloads' / 'latest_enoking_products.xlsx'); _copy(output_dir / 'latest_opportunities.csv', public_dir / 'downloads' / 'latest_opportunities.csv')\n    return meta\ndef main():\n    print(json.dumps(build_static_site(), ensure_ascii=False, indent=2)); return 0\nif __name__ == '__main__':\n    raise SystemExit(main())\n""")